        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="IOBPv300GetPrivateAccountIdsbyBankIdApiResponse"/>?&gt;</returns>
        Task<IOBPv300GetPrivateAccountIdsbyBankIdApiResponse?> OBPv300GetPrivateAccountIdsbyBankIdOrDefaultAsync(string bankid, System.Threading.CancellationToken cancellationToken = default);

        /// <summary>
