        Task<IOBPv300PrivateAccountsAtOneBankApiResponse> OBPv300PrivateAccountsAtOneBankAsync(string bankid, System.Threading.CancellationToken cancellationToken = default);

        /// <summary>
        /// Get Accounts at Bank (Minimal)
