        private void ValidateOBPv400AnswerTransactionRequestChallenge(string bankid, string accountid, string viewid, string transactionrequesttype, string transactionrequestid, OBPv400AnswerTransactionRequestChallengeRequest oBPv400AnswerTransactionRequestChallengeRequest)
        {
            if (bankid == null)
                throw new ArgumentNullException(nameof(bankid));

            if (accountid == null)
                throw new ArgumentNullException(nameof(accountid));

            if (viewid == null)
                throw new ArgumentNullException(nameof(viewid));

            if (transactionrequesttype == null)
                throw new ArgumentNullException(nameof(transactionrequesttype));

            if (transactionrequestid == null)
                throw new ArgumentNullException(nameof(transactionrequestid));

            if (oBPv400AnswerTransactionRequestChallengeRequest == null)
                throw new ArgumentNullException(nameof(oBPv400AnswerTransactionRequestChallengeRequest));
        }

